# Assign a policy initiative at Corp MG and override parameters for Corp-Prod

data "azurerm_management_group" "corp" { name = "mg-corp" }
data "azurerm_management_group" "corp_prod" { name = "mg-corp-prod" }

# Assign the baseline initiative at Corp MG
resource "azurerm_management_group_policy_assignment" "corp_baseline" {
  name                 = "corp-baseline"
  management_group_id  = data.azurerm_management_group.corp.id
  policy_definition_id = azurerm_policy_set_definition.corp_baseline.id
  parameters = jsonencode({
    listOfAllowedLocations = { value = ["eastus", "eastus2", "westeurope"] }
    tagName               = { value = "environment" }
  })
}

# Assign an additional deny policy only at Corp-Prod (stricter than Corp)
resource "azurerm_management_group_policy_assignment" "corp_prod_deny_public_ip" {
  name                 = "deny-public-ip"
  management_group_id  = data.azurerm_management_group.corp_prod.id
  policy_definition_id = "/providers/Microsoft.Authorization/policyDefinitions/65523614-dabb-4b52-a6ef-5c7e235b3a74"
  enforce              = true
}

# Create an exemption for a resource group from the tag policy
resource "azurerm_resource_group_policy_exemption" "legacy_tag_waiver" {
  name                 = "legacy-tag-waiver"
  resource_group_id    = data.azurerm_resource_group.legacy.id
  policy_assignment_id = azurerm_management_group_policy_assignment.corp_baseline.id
  exemption_category   = "Waiver"
  expires_on           = "2026-12-31T00:00:00Z"
  description          = "Legacy RG: migrating resources in Q4 2026"
}

{
  "mode": "All",
  "displayName": "Deploy diagnostic settings for Storage Accounts to Log Analytics",
  "policyRule": {
    "if": {
      "field": "type",
      "equals": "Microsoft.Storage/storageAccounts"
    },
    "then": {
      "effect": "DeployIfNotExists",
      "details": {
        "type": "Microsoft.Insights/diagnosticSettings",
        "name": "setByPolicy",
        "existenceCondition": {
          "allOf": [
            { "field": "Microsoft.Insights/diagnosticSettings/workspaceId", "like": "*" },
            { "field": "Microsoft.Insights/diagnosticSettings/logs[*].enabled", "equals": "true" }
          ]
        },
        "roleDefinitionIds": [
          "/providers/Microsoft.Authorization/roleDefinitions/b24988ac-6180-42a0-ab88-20f7382dd24c"
        ],
        "deployment": {
          "properties": {
            "mode": "incremental",
            "template": {
              "$schema": "https://schema.management.azure.com/schemas/2019-04-01/deploymentTemplate.json#",
              "contentVersion": "1.0.0.0",
              "parameters": {
                "resourceName": { "type": "string" },
                "workspaceId":  { "type": "string" }
              },
              "resources": [{
                "type": "Microsoft.Storage/storageAccounts/providers/diagnosticSettings",
                "apiVersion": "2021-05-01-preview",
                "name": "[concat(parameters('resourceName'), '/Microsoft.Insights/setByPolicy')]",
                "properties": {
                  "workspaceId": "[parameters('workspaceId')]",
                  "logs": [{ "categoryGroup": "allLogs", "enabled": true }],
                  "metrics": [{ "category": "Transaction", "enabled": true }]
                }
              }]
            }
          }
        }
      }
    }
  }
}
